fun main() {
    var greeting: String? = null
    println(greeting?.length)  // null
    println(greeting ?: "Hello, Guest!")  // Hello, Guest!

    greeting = "Hello, Kotlin!"
    println(greeting?.length)  // 15
    greeting?.let {
        println("Message: $it")
    }

    val email: String? = "user@test.com"
    val display = email ?: "no email"
    println(display)
}
